from dataclasses import dataclass, field
from enum import Enum
from datetime import date, timedelta
from typing import Optional

class RAGStatus(Enum):
    GREEN = "green"
    AMBER = "amber"
    RED   = "red"

@dataclass
class ScheduleIndicators:
    critical_path_slip_days: int = 0
    near_critical_float_weeks: Optional[int] = None  # None = not near-critical
    launch_date_at_risk: bool = False

@dataclass
class BudgetIndicators:
    spend_variance_pct: float = 0.0   # positive = over budget
    forecast_over_budget: bool = False

@dataclass
class ScopeIndicators:
    features_deferred: int = 0
    core_capability_removed: bool = False

@dataclass
class DependencyIndicators:
    blocked_critical_deps: int = 0
    at_risk_no_mitigation: int = 0


def compute_schedule_rag(ind: ScheduleIndicators) -> RAGStatus:
    if ind.launch_date_at_risk or ind.critical_path_slip_days > 7:
        return RAGStatus.RED
    if ind.critical_path_slip_days > 3 or (
        ind.near_critical_float_weeks is not None and ind.near_critical_float_weeks < 2
    ):
        return RAGStatus.AMBER
    return RAGStatus.GREEN


def compute_budget_rag(ind: BudgetIndicators) -> RAGStatus:
    if ind.forecast_over_budget or ind.spend_variance_pct > 15:
        return RAGStatus.RED
    if 5 < ind.spend_variance_pct <= 15:
        return RAGStatus.AMBER
    return RAGStatus.GREEN


def compute_scope_rag(ind: ScopeIndicators) -> RAGStatus:
    if ind.core_capability_removed:
        return RAGStatus.RED
    if ind.features_deferred >= 2:
        return RAGStatus.AMBER
    return RAGStatus.GREEN


def compute_dependency_rag(ind: DependencyIndicators) -> RAGStatus:
    if ind.blocked_critical_deps > 0:
        return RAGStatus.RED
    if ind.at_risk_no_mitigation > 0:
        return RAGStatus.AMBER
    return RAGStatus.GREEN


def rollup_program_rag(
    schedule: RAGStatus,
    budget: RAGStatus,
    scope: RAGStatus,
    dependency: RAGStatus,
) -> RAGStatus:
    """Worst-case rollup: any RED → program RED; any AMBER → AMBER."""
    all_rags = [schedule, budget, scope, dependency]
    if any(r == RAGStatus.RED for r in all_rags):
        return RAGStatus.RED
    if any(r == RAGStatus.AMBER for r in all_rags):
        return RAGStatus.AMBER
    return RAGStatus.GREEN

from dataclasses import dataclass

@dataclass
class EscalationAction:
    level: int           # 1=team lead, 2=director, 3=vp/cto, 4=exec emergency
    notify: list[str]    # roles to notify
    deadline_hours: int  # how quickly this must happen
    required_content: list[str]

ESCALATION_LADDER = {
    RAGStatus.RED: [
        EscalationAction(
            level=1,
            notify=["program-manager", "team-lead"],
            deadline_hours=4,
            required_content=["root cause", "impact statement", "mitigation options"],
        ),
        EscalationAction(
            level=2,
            notify=["director", "program-sponsor"],
            deadline_hours=24,
            required_content=["root cause", "business impact", "recommended decision"],
        ),
    ],
    RAGStatus.AMBER: [
        EscalationAction(
            level=1,
            notify=["program-manager", "team-lead"],
            deadline_hours=48,
            required_content=["risk description", "mitigation plan", "monitoring cadence"],
        ),
    ],
    RAGStatus.GREEN: [],   # no escalation
}

def get_escalation_actions(rag: RAGStatus) -> list[EscalationAction]:
    return ESCALATION_LADDER.get(rag, [])

from datetime import date

def auto_compute_weekly_rag(
    initiative_id: str,
    jira_metrics: dict,       # from Jira API: {"critical_path_slip": 2, "deferred_stories": 1}
    finance_metrics: dict,    # from finance system: {"variance_pct": 7.5}
    dep_registry: dict,       # from dependency registry: {"blocked": 0, "at_risk_no_mit": 1}
) -> dict:
    """Compute RAG automatically from data sources without team lead input."""
    sched = ScheduleIndicators(
        critical_path_slip_days=jira_metrics.get("critical_path_slip", 0),
        launch_date_at_risk=jira_metrics.get("launch_at_risk", False),
    )
    budg = BudgetIndicators(
        spend_variance_pct=finance_metrics.get("variance_pct", 0.0),
        forecast_over_budget=finance_metrics.get("forecast_over", False),
    )
    scope = ScopeIndicators(
        features_deferred=jira_metrics.get("deferred_stories", 0),
        core_capability_removed=jira_metrics.get("core_removed", False),
    )
    dep = DependencyIndicators(
        blocked_critical_deps=dep_registry.get("blocked", 0),
        at_risk_no_mitigation=dep_registry.get("at_risk_no_mit", 0),
    )

    sched_rag = compute_schedule_rag(sched)
    budg_rag  = compute_budget_rag(budg)
    scope_rag = compute_scope_rag(scope)
    dep_rag   = compute_dependency_rag(dep)
    prog_rag  = rollup_program_rag(sched_rag, budg_rag, scope_rag, dep_rag)

    return {
        "initiative_id": initiative_id,
        "as_of": date.today().isoformat(),
        "rag": {
            "schedule": sched_rag.value,
            "budget":   budg_rag.value,
            "scope":    scope_rag.value,
            "dependency": dep_rag.value,
            "program":  prog_rag.value,
        },
        "escalation_required": prog_rag in (RAGStatus.RED, RAGStatus.AMBER),
    }

# Example
result = auto_compute_weekly_rag(
    initiative_id="sales-ai-proposal-gen",
    jira_metrics={"critical_path_slip": 4, "deferred_stories": 0, "launch_at_risk": False},
    finance_metrics={"variance_pct": 3.0},
    dep_registry={"blocked": 0, "at_risk_no_mit": 1},
)
# → {"rag": {"schedule": "amber", "budget": "green", "scope": "green",
#            "dependency": "amber", "program": "amber"}, "escalation_required": True}
